import type { SupportedCurrency } from "@/shared/config/currency-config";
import type { UserRole } from "@/shared/types";

export interface Country {
  id: string;
  name: string;
  alpha2: string;
  alpha3: string;
  ioc: string;
}

export interface Address {
  id: string;
  country: Country;
  addressType?: string;
  state: string;
  city: string;
  zip: string;
  addressLine1: string;
  addressLine2: string;
  landmark?: string;
  latitude?: number;
  longitude?: number;
  isPrimary?: boolean;
}

export interface AdminRole {
  id: string;
  name: string;
  permissions: string[];
}

export interface Admin {
  id: string;
  adminRoles: AdminRole[];
  permissions: string[];
}

export interface Profile {
  id: string;
  firstName: string;
  lastName: string;
  patronymic: string | null;
  email: string;
  phone: string;
  photoFileId: string | null;
  roles: UserRole[];
  selectedRole: UserRole;
  admin?: Admin;
  createdAt: string;
  updatedAt: string;
}

export interface UpdateProfileDto {
  firstName: string;
  lastName: string;
  patronymic?: string;
}

export interface UpdateProfilePhotoDto {
  photoFileId: string | null;
}

export interface UpsertAddressDto {
  id?: string;
  addressType?: string;
  countryId: string;
  state: string;
  city: string;
  zip: string;
  addressLine1: string;
  addressLine2: string;
  landmark?: string;
  latitude?: number;
  longitude?: number;
  isPrimary?: boolean;
}

export interface UserNotificationsSetting {
  general: boolean;
  buyback: boolean;
  authenticator: boolean;
  accountSecurity: boolean;
}

export enum UserSetting {
  Notifications = "NOTIFICATIONS",
  Currency = "CURRENCY",
}

export interface UserSettings {
  [UserSetting.Notifications]: UserNotificationsSetting;
  [UserSetting.Currency]: SupportedCurrency;
}

export interface UpdateSettingsDto {
  [UserSetting.Notifications]?: UserNotificationsSetting;
  [UserSetting.Currency]?: SupportedCurrency;
}

